mapper.select:
SELECT t.*
FROM eb_approve t

	AND t.deleted_at IS NULL

		AND t.name LIKE CONCAT('%', #{query.nameLike}, '%')


		AND t.types = #{query.filterTypes}


		AND t.status = #{query.filterStatus}


		AND t.examine = #{query.filterExamine}


		AND t.entid = #{query.filterEntid}


ORDER BY t.sort ASC, t.id DESC
